import React from "react";
import { Container } from "react-bootstrap";

const Footer = () => {
  return (
    <Container fluid className="text-center py-3" style={{ backgroundColor: "#5d5c5c", color: "white" }}>
      <p className="mb-0">© 2024 Vanamu Sumalatha. All rights reserved.</p>
    </Container>
  );
};

export default Footer;
